window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]=window.__LIBQ["the-gioi-hoan-my"]["q02"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]["techniques"]={"updatedAt":"2026-07-04","count":132,"techniques":[{"id":"tran-vuc-khu-thu-tam","name":"Trận vực","loai":"khac","loaiLabel":"Trận pháp","hePhai":"Bổ Thiên các","soHuu":[],"blurb":"Trận pháp dựa vào phù cốt để duy trì hiệu lực ngăn cửa ải các khu thí luyện.","detail":"Trận pháp bao phủ các khu thí luyện, dựa vào phù cốt chôn dưới đất để duy trì hiệu lực ngăn cửa ải. Khi phù cốt khu thứ tám bị Nhóc tỳ cướp sạch, trận vực mất đi hiệu lực, khiến tổ đoàn hơn 8900 người xông cửa ải cuối thành công.","nguon":["@c0102"]},{"id":"am-ba-cong","name":"Âm Ba Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Tiêu Thiên"],"blurb":"Công pháp của Tiêu Thiên (thiếu niên áo bạc); khi phát ra tiếng rống thì chấn động sơn hà, uy hiếp các thiếu niên xung quanh. (+) Công pháp âm ba tương tự Chân Hống khiếu, dùng để chấn nhiếp và đánh thức thần trí đối phương. [CAN-SOAT-GOP]","detail":"Âm Ba Công là công lực của Tiêu Thiên. Trong chiến trường thứ hai, khi tỉnh dậy phát hiện bị đập ngất và mọc cục u trên trán, Tiêu Thiên nổi điên rống to, toàn thân giăng đầy phù văn màu bạc, tiếng rống chấn động sơn hà khiến các thiếu niên gần đó kinh hãi vì đủ sức quét ngang bọn họ. Tiếng rống dồi dào trung khí này về sau khiến các trưởng lão Bổ Thiên Các ngộ nhận hắn là kỳ tài ngút trời hiếm thấy.","nguon":["@c0103","@c0266"]},{"id":"khuyen-ma-cong","name":"Khuyển Ma Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Thượng cổ","soHuu":[],"blurb":"Công pháp thời Thượng cổ, được nhắc để ví dáng điên cuồng gào thét của Trác Vân.","detail":"Công pháp thời Thượng cổ được một đứa trẻ bộ lạc nhắc tới để ví với dáng vẻ điên cuồng gào thét của Trác Vân trưởng lão khi mất Hắc Sát Liên; không ai thực sự thi triển trong chương.","nguon":["@c0105"]},{"id":"van-tu-hoan-cot","name":"Văn tự Hoàn Cốt","loai":"cong-phap","loaiLabel":"Công pháp nhập môn","hePhai":"Bổ Thiên các","soHuu":["Thạch Hạo"],"blurb":"Văn tự nhập môn được hai trưởng lão Hùng Phi và Trác Vân giảng cho tân đệ tử Bổ Thiên các.","detail":"Là nội dung giảng dạy đầu tiên cho trăm tân đệ tử của Hùng Phi và Trác Vân; hai trưởng lão chỉ giảng rồi vội rời đi, vài ngày mới gặp một lần.","nguon":["@c0106"]},{"id":"kim-tuyen-ba-van-cong","name":"Kim Tuyền Ba Văn Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Kim Sí Đại Bằng","soHuu":[],"blurb":"Công pháp hộ thể thoát thai từ Phù Văn hộ thể của Kim Sí Đại Bằng, hiện kim quang xoáy vòng vàng trên thân xoắn nát mọi công kích.","detail":"Học từ một mảnh Cốt Thư (xương vàng dính tro) trong Tàng Kinh các Bổ Thiên các, chỉ tìm được một quyển. Khi thi triển, thân hiện kim quang Phù Văn vô tận xoáy tròn, xoắn nát trường mâu ngưng tụ. Nếu tìm được phần sau sẽ vô cùng khủng bố.","nguon":["@c0108","@c0178","@c0179"]},{"id":"ngu-long-phu-van","name":"Ngư Long Phù Văn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Chu Vũ Hào"],"blurb":"Phù Văn hóa Ngư Long phát sáng đánh bay đối thủ, kèm ám kình khiến bên ngoài không nhận ra sát thương thật.","detail":"Chu Vũ Hào vẽ đường cong như Ngư Long vẫy đuôi, bắn Phù Văn vô tận hóa con Ngư Long phát sáng đánh bay Thanh Phong; dùng kèm ám kình chấn động khí huyết khiến ngũ tạng như bể nát mà bề ngoài không ai phát hiện.","nguon":["@c0108"]},{"id":"phu-chuong","name":"Phù Chưởng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Phù Văn","soHuu":["Thạch Hạo"],"blurb":"Bàn tay nhỏ do Phù Văn hóa thành, đánh gãy xương đối thủ.","detail":"Thần thông do Phù Văn ngưng tụ thành một bàn tay nhỏ thần bí, đánh gãy toàn bộ xương sườn trái Chu Vũ Hào, sau đó đánh gãy hơn mười cây xương của hai người nhảy vào cứu; là đòn Thạch Hạo âm thầm dùng để trọng thương ba người trong xung đột.","nguon":["@c0109"]},{"id":"than-thong-nuot-linh-tuoc","name":"Thần thông nuốt của Linh Tước năm màu","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Yêu thú","soHuu":["Thiếu niên nuôi Linh Tước"],"blurb":"Thần thông yêu thú của con Linh Tước năm màu (Ma Cầm): há mồm hút thành vòng xoáy kinh khủng.","detail":"Con Linh Tước năm màu bay lên há mồm hút thành vòng xoáy kinh khủng, nuốt mấy chục người và nghiền nát tất cả trong miệng, rồi bay trở về vai chủ nhân; cả phố lặng ngắt vì kinh hãi.","nguon":["@c0115"]},{"id":"thu-toc-hoa-cay-an-than","name":"Thụ tộc hóa cây ẩn thân","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thụ tộc","soHuu":["Cao thủ Thụ tộc"],"blurb":"Thần thông chủng tộc của cao thủ Thụ tộc, hóa thành cây cổ thụ lẫn vào rừng để đánh lén.","detail":"Cao thủ Thụ tộc hóa thành cây cổ thụ lẫn vào rừng rất khó phát hiện, dùng để phục kích đánh lén; khi bị Thạch Hạo đụng gãy làm hai thì hiện nguyên hình là thụ nhân.","nguon":["@c0117"]},{"id":"phun-lua-nung-chay-da","name":"Phun lửa nung chảy đá","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Đại Hồng"],"blurb":"Thần thông của chim lửa Đại Hồng, phun vô số ánh lửa thiêu cự thạch thành dung nham.","detail":"Con chim lớn đỏ rực phun vô số ánh lửa, thiêu cự thạch thành dung nham; dùng để chống trả khi bị Thạch Hạo ném đá đuổi bắt.","nguon":["@c0117"]},{"id":"ma-cam-thoi-thai-co","name":"Ma Cầm thời Thái Cổ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Nhóc tỳ xòe năm ngón, ngân quang đan dệt như tia chớp tạo thành con Ma Cầm bay lên đánh trả.","detail":"Thần thông triệu hoán: nhóc tỳ xòe năm ngón, ánh sáng ngân đan dệt như tia chớp tạo thành con Ma Cầm thời Thái Cổ bay lên đánh Hỏa Vân Tước trong tiểu thế giới.","nguon":["@c0118"]},{"id":"tia-chop-vang-cuc-toc","name":"Tia chớp vàng cực tốc","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Lòng bàn tay nhóc tỳ phát sáng trong suốt, bắn tia chớp màu vàng tốc độ cực điểm.","detail":"Thần thông của nhóc tỳ: lòng bàn tay phát sáng trong suốt, bắn ra tia chớp màu vàng tốc độ cực điểm nổ trên người Hỏa Vân Tước làm nổ lông vũ chim.","nguon":["@c0118"]},{"id":"bao-thuat-toan-nghe-vuong","name":"Bảo thuật Toan Nghê Vương","loai":"bi-thuat","loaiLabel":"Bảo thuật Thái Cổ di chủng","phamCap":"Thái Cổ","hePhai":"Toan Nghê","soHuu":["Thạch Hạo"],"blurb":"Hàm nghĩa của Toan Nghê — loại Thái Cổ di chủng mạnh nhất; kết hợp Cốt Kính thôi thúc ra tia chớp vàng có thần uy kinh người.","detail":"Bảo thuật truyền thừa của Toan Nghê Vương, được Thạch Hạo triển qua Cốt Kính: xoay mặt ngược gương thôi thúc hàm nghĩa Toan Nghê phóng tia chớp vàng thần uy. Sinh linh màu bạc kinh sợ nhận ra khi bị Cốt Kính phản chiếu làm tróc vảy.","nguon":["@c0119"]},{"id":"chuong-phu-van-tia-chop-vang","name":"Chưởng Phù Văn tia chớp vàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Bổ Thiên các","soHuu":["Thạch Hạo"],"blurb":"Chưởng công kích Phù Văn, khi đánh ra Phù Văn đầy trời và tia chớp vàng óng xông ra.","detail":"Nhóc tỳ đánh một chưởng, Phù Văn đầy trời, đạo âm vang lên, tia chớp màu vàng óng xông ra hóa đối thủ thành than cốc.","nguon":["@c0120"]},{"id":"muoi-tia-chop-tho-to","name":"Mười tia chớp thô to","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Bổ Thiên các","soHuu":["Thạch Hạo"],"blurb":"Thần thông công kích, mười ngón cùng mở bắn mười tia chớp vạch ngang trời.","detail":"Nhóc tỳ giơ mười ngón cùng mở ra bắn mười tia chớp thô to vạch ngang trời, xuyên thủng mấy Dị tộc hóa thành tro tàn.","nguon":["@c0120"]},{"id":"nguyet-ban","name":"Nguyệt bàn","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Mâm nguyệt tròn màu bạc tỏa hào quang lạnh bung sau lưng nhóc tỳ để phòng ngự.","detail":"Nhóc tỳ bung ra sau lưng một Nguyệt bàn hình tròn màu bạc tỏa hào quang lạnh, chắn ánh lửa đầy trời của Hỏa Linh Nhi khi nàng phun lửa hóa Chu Tước tấn công.","nguon":["@c0121"]},{"id":"nghich-chuyen","name":"Nghịch chuyển","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Đòn sát thủ dùng bảo cốt Toan Nghê tế thành gương, cuốn ngược bão đá về phía đối thủ.","detail":"Nhóc tỳ dùng bảo cốt Toan Nghê tế thành một tấm gương, chiếu Phù Văn ngăn bão táp đá rồi cuốn ngược tất cả trở lại về phía Hoàng Kim sư tử chín đầu, sau đó nhảy lên tóc mai nó.","nguon":["@c0121"]},{"id":"chin-phi-kiem-hoang-kim","name":"Chín phi kiếm hoàng kim","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hoàng Kim sư tử chín đầu"],"blurb":"Chín cái đầu của Hoàng Kim sư tử mỗi đầu phun ra một thanh phi kiếm màu hoàng kim chém tới.","detail":"Khi giao chiến, chín cái đầu của Hoàng Kim sư tử chín đầu mỗi đầu phun ra một thanh phi kiếm màu hoàng kim rực rỡ, tổng cộng chín phi kiếm chém về phía nhóc tỳ.","nguon":["@c0121"]},{"id":"su-hong-cong","name":"Sư Hống công","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo Thuật","hePhai":"Dòng dõi Hoàng Kim sư tử","soHuu":["Sư Tử chín đầu"],"blurb":"Bảo Thuật âm ba của dòng dõi Hoàng Kim sư tử: chín đầu lâu đồng loạt gào thét phát chín gợn sóng màu vàng thành thực thể che kín trời.","detail":"Thần công riêng của dòng dõi Hoàng Kim sư tử. Khi thi triển, chín đầu lâu cùng lúc gào thét phát ra chín luồng gợn sóng màu vàng như biển gầm che kín cả bầu trời, đại địa nứt toác; chỉ dòng dõi Hoàng Kim sư tử mới dùng được.","nguon":["@c0122"]},{"id":"vo-uy-su-tu-an","name":"Vô Úy Sư Tử ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông trấn tộc","hePhai":"Dòng dõi Hoàng Kim sư tử","soHuu":["Sư Tử chín đầu"],"blurb":"Thần thông trấn tộc của dòng dõi Hoàng Kim sư tử, hiện sư tử con vàng, có thể đào núi lấp biển, hô mưa gọi gió, quấy nhiễu sấm sét cửu thiên.","detail":"Pháp ấn trấn tộc của dòng dõi Hoàng Kim sư tử, thường phải trưởng thành mới thi triển được nên khiến các thiên tài Bổ Thiên các mặt trắng bệch. Khi thi triển hiện ra một sư tử con vàng uy năng lớn. Trong chương này bị Nhóc tỳ vận Nguyên Thủy Chân Giải và Chiến Thần Đồ Lục, tổ hợp Phù Văn thường mà hóa giải.","nguon":["@c0122"]},{"id":"bao-thuat-thanh-lan-ung","name":"Bảo Thuật Thanh Lân Ưng","cn":"","loai":"cong-phap","loaiLabel":"Bảo Thuật","phamCap":"Bảo Thuật","hePhai":"Dòng tộc Thanh Lân Ưng","soHuu":["Thạch Hạo"],"blurb":"Bảo Thuật riêng của dòng tộc Thanh Lân Ưng, Nhóc tỳ dùng để bảo vệ cơ thể khi lao vào giao chiến.","detail":"Bảo Thuật thuộc dòng tộc Thanh Lân Ưng, được Nhóc tỳ sử dụng để bảo vệ cơ thể khi hóa Lôi thần vàng lao vào đánh Hoàng Kim sư tử, phối hợp cùng Bảo Thuật Toan Nghê tạo sương mù che mắt.","nguon":["@c0122"]},{"id":"cot-tien-mau-vang","name":"Cốt Tiễn màu vàng","cn":"","aliases":["Long Giao tiễn","Cốt Tiễn"],"loai":"bi-thuat","loaiLabel":"Bí thuật / Pháp bảo tiễn","phamCap":"Vượt cấp bậc bản thân người dùng","hePhai":"","soHuu":["Nhóc tỳ (thiếu niên Nhân tộc)"],"blurb":"Tiễn xương màu vàng của nhóc tỳ, khẽ kêu keng rồi hóa hai giao long chém rụng đầu lâu Sư Tử chín đầu.","detail":"Cốt Tiễn màu vàng — còn gọi Long Giao tiễn — là tiễn xương của nhóc tỳ Nhân tộc. Khi thi triển, tiễn phát ra tiếng keng rồi hóa thành hai con giao long, quét chém rụng bốn đầu lâu Sư Tử chín đầu (hai đầu bên trái rồi hai đầu bên phải). Uy lực vượt xa cấp bậc bản thân Sư Tử; Sư Tử không có nghịch thiên như nhóc tỳ nên không thể lấy bảo thuật cứng rắn mà chống đỡ Long Giao tiễn được. Đây là một trong những thủ đoạn hạ gục Sư Tử chín đầu.","nguon":["@c0123"]},{"id":"chin-hat-niem-chau","name":"Chín hạt niệm châu","cn":"","aliases":["Niệm châu"],"loai":"bi-thuat","loaiLabel":"Bảo thuật / Thủ đoạn","phamCap":"Vượt cấp bậc bản thân Sư Tử","hePhai":"","soHuu":["Sư Tử chín đầu (Hoàng Kim sư tử)"],"blurb":"Chín hạt niệm châu do Sư Tử chín đầu phóng ra, mỗi hạt lóng lánh như một thế giới nhỏ, trấn áp đối thủ như một mảnh thế giới.","detail":"Chín hạt niệm châu là thủ đoạn/bảo cụ của Sư Tử chín đầu (Hoàng Kim sư tử). Mỗi hạt lóng lánh như một thế giới nhỏ, sương mù lượn quanh, tỏa lực trấn áp khiến đối thủ như đang đối kháng cùng một mảnh thế giới. Khi nhóc tỳ hóa thân hải dương sấm sét dùng bảo thuật cứng rắn chống lại chín hạt niệm châu, khóe miệng nó bị chấn động rỉ ra một vệt máu tươi, hai bên lực lượng tương đương. Đi kèm chín răng nanh màu vàng của Sư Tử; đều vượt cấp bậc bản thân nó.","nguon":["@c0123"]},{"id":"u-lan-thao-thuat","name":"U Lan Thảo","loai":"bi-thuat","loaiLabel":"Bí thuật truy tung","phamCap":"Không rõ","hePhai":"","soHuu":["Hỏa Linh Nhi"],"blurb":"Loại thảo dược dùng để lần theo mùi: vật bị dính một giọt sẽ tỏa mùi thơm nhạt trong mấy ngày.","detail":"Đám người đội nón đen vẩy vài giọt U Lan Thảo lên trứng thần, khiến nó tỏa mùi thơm nhạt lưu lại mấy ngày để lần theo dấu vết. Nhờ vật này mà đoàn Hỏa Linh Nhi truy được nhóc tỳ dù nó đã nhảy xuống sông cắt mùi.","nguon":["@c0124"]},{"id":"tham-cot-phap","name":"Tham Cốt pháp","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Nguyên Thủy Chân Giải","soHuu":["Thạch Hạo"],"blurb":"Pháp thăm dò cốt cách trong Nguyên Thủy Chân Giải.","detail":"Pháp môn thăm dò cốt cách nằm trong Nguyên Thủy Chân Giải; Thạch Hạo dùng dò khắp cốt cách sói con nhưng không phát hiện nguyên thủy phù cốt lẫn ấn ký, chỉ thấy máu huyết mạnh mẽ.","nguon":["@c0125"]},{"id":"co-phap-hoa-hung-thu-thai-co","name":"Cổ pháp hóa hung thú Thái Cổ thuần huyết","loai":"cong-phap","loaiLabel":"Cổ pháp","phamCap":"Không rõ","hePhai":"Tộc Sư Tử chín đầu","soHuu":["Sư Tử chín đầu"],"blurb":"Cổ pháp tộc Sư Tử giúp tu hành hóa thành hung thú Thái Cổ thuần huyết.","detail":"Pháp môn bộ tộc Sư Tử chín đầu tìm được, giúp tu hành dần hóa thành hung thú Thái Cổ thuần huyết, mạnh gần vô địch; đồng lứa từng giết thần, không kém Kim Sí Đại Bằng.","nguon":["@c0125"]},{"id":"nam-tang-sat-tran-phu-van","name":"Năm tầng sát trận Phù Văn","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Trận cổ","hePhai":"","soHuu":[],"blurb":"Trận cổ ở vùng ngập nước, kích hoạt liên tiếp năm tầng khi có kẻ tiến vào, biến khu vực thành kiếp thổ.","detail":"Trận Phù Văn cổ giấu trong vùng ngập nước; khi có kẻ tiến vào thì kích hoạt liên tiếp năm tầng, thần mang hóa thành mũi tên, chiến mâu, thần kiếm, búa nhỏ san bằng núi rừng, biến nơi này thành kiếp thổ nhằm tiêu diệt kẻ trong trận. Thạch Hạo và Sư Tử chín đầu phá ra ngoài với vài vết thương nhẹ.","nguon":["@c0126"]},{"id":"than-nang-tam-mua-vu-toc","name":"Thần năng tắm mưa (Vũ tộc)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Vũ tộc","soHuu":["Mười người Vũ tộc"],"blurb":"Tương truyền Vũ tộc tắm mình trong mưa lớn thì thần năng tăng lên một bước dài.","detail":"Đặc tính chủng tộc của Vũ tộc: khi tắm mình trong mưa lớn, khí tức và thần năng tăng vượt bậc, hiện lên bảo quang. Mây mù, mưa lớn tại chỗ do nhóm mười người Vũ tộc dẫn tới để tăng cường thực lực khi phục kích.","nguon":["@c0126"]},{"id":"ta-phong-te-vu-tram-tinh-nguyet","name":"Tà phong tế vũ Trảm tinh nguyệt","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Mười người Vũ tộc"],"blurb":"Bảo Thuật hợp lực của Vũ tộc, biến mưa thành vô số lưỡi dao sắc bén.","detail":"Mười người Vũ tộc đồng hô, biến cơn mưa thành vô số lưỡi dao sắc bén che kín trời đâm thủng núi đá, phối hợp cùng thủy hệ Phù Văn đè ép đối thủ.","nguon":["@c0127"]},{"id":"thong-thien-dong-dia","name":"Thông thiên động địa","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Mười người Vũ tộc"],"blurb":"Bảo Thuật Vũ tộc khơi thông hồ lớn cuộn tới như biển giận.","detail":"Mười người Vũ tộc đồng hô, khơi thông cả một hồ lớn cuộn tới như biển giận, Phù Văn ngập nước bao phủ, uy thế mãnh liệt.","nguon":["@c0127"]},{"id":"bao-thuat-phu-van-hop-luc-vu-toc","name":"Bảo Thuật Phù Văn hợp lực (Vũ tộc)","loai":"bi-thuat","loaiLabel":"Thuật trận hợp kích","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Mười người Vũ tộc"],"blurb":"Mười người Vũ tộc thi triển một môn Bảo Thuật, uy lực tương đương hai ba mươi người cộng lại.","detail":"Không phải phép cộng đơn thuần, Phù Văn kết hợp khiến uy lực của mười người tương đương với hai ba mươi người cộng lại, dâng lên những trận sóng lam tầng tầng phá nát cả ngọn núi nhỏ.","nguon":["@c0127"]},{"id":"thong-linh-than-giac","name":"Thông Linh Thần Giác","loai":"than-thong","loaiLabel":"Thần thông / Thiên phú","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Giác quan thần kỳ thông linh của Vũ Tử Mạch, đôi khi hiểu được chút nhân quả.","detail":"Thiên phú giác quan thần kỳ của Vũ Tử Mạch, có thể thông linh và đôi khi hiểu được chút nhân quả. Tuy nhiên nàng không nhìn thấu được nhóc tỳ (Thạch Hạo) lẫn Thạch Nghị vì cả hai đều bị một luồng sương mù bao phủ.","nguon":["@c0128"]},{"id":"bao-thuat-thong-linh","name":"Bảo Thuật Thông Linh","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"aliases":["Nhất Thế Họa Quyển"],"blurb":"Bảo thuật dùng ký tự Thông Linh màu xanh dệt quyển sách cổ Phù Văn để phong ấn địch, Phù Văn bị phá thì tái sinh tại chỗ, gần như bất hủ.","detail":"Vũ Tử Mạch triển khai chữ Thông Linh — ký tự màu xanh hình lập phương như có sinh mạng, mở ra quyển sách cổ Phù Văn. Thần thông “Nhất Thế Họa Quyển” xếp ký tự thành bức họa như “Phong Ma quyển đến từ Trời xanh” để phong ấn đối thủ; Phù Văn bị phá lại tái sinh tại chỗ, quyển sách cổ như gánh chịu lực lượng năm tháng nên gần như bất hủ.","nguon":["@c0128"]},{"id":"hoa-vu-thanh-binh-trong-mua-sinh-dien","name":"Hóa vũ thành binh / Trong mưa sinh điện","loai":"cong-phap","loaiLabel":"Công pháp Vũ tộc","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Công pháp căn bản siêu thoát của Vũ tộc: biến mưa thành vũ khí và trong mưa sinh ra lôi điện Thần uy trời đất.","detail":"Vũ Tử Mạch hóa mưa thành cánh hoa/phi kiếm tấn công. Đặc biệt “Trong mưa sinh điện”: mây đen tụ, tia chớp xanh mang Thần uy trời đất giáng xuống, phá nát một tòa núi nhỏ thành bốn mảnh. Đây là căn bản để Vũ tộc siêu thoát bản thân.","nguon":["@c0128"]},{"id":"coi-xay-mau-bac","name":"Cối xay màu bạc","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Cặp cối xay bạc chuyển động nghiền ép Phù Văn, cuối cùng nổ tung phá vỡ quyển sách cổ của Vũ Tử Mạch.","detail":"Nhóc tỳ (Thạch Hạo) tạo cặp cối xay màu bạc nghiền ép quyển sách cổ Phù Văn của Vũ Tử Mạch. Cối xay cuối cùng nổ tung, phá vỡ quyển sách cổ khiến Bảo Thuật Thông Linh mất hiệu lực.","nguon":["@c0128"]},{"id":"loi-dien-mau-vang","name":"Lôi điện màu vàng","loai":"bi-thuat","loaiLabel":"Bảo thuật lôi điện","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Mười tia chớp vàng, lôi quang thô to của nhóc tỳ, khắc chế công pháp nước của Vũ tộc.","detail":"Nhóc tỳ (Thạch Hạo) hiểu bảo thuật Lôi điện; phóng mười tia chớp vàng phá Phù Văn và tự phát điện màu vàng đánh thẳng về phía trước, khắc chế công pháp nước-lôi điện của Vũ tộc, đánh Vũ Tử Mạch bị thương ho ra máu.","nguon":["@c0128"]},{"id":"phu-van-chu-co-vu-tu-mach","name":"Phù Văn (chữ cổ)","loai":"than-thong","loaiLabel":"Thuật / Thần thông","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Chữ cổ liên miên phát ra âm thanh và ánh sáng chói mắt, tạm thời chặn Lôi đình thần uy.","detail":"Phù Văn chữ cổ của thiếu nữ Vũ tộc phát ra âm thanh và ánh sáng chói mắt, tạm thời chặn lại Lôi đình thần uy. Khi chủ nhân giận dữ thì Phù Văn kịch liệt lay động, quyển sách cổ nhiều màu lúc sáng lúc tối, trông rất bất ổn.","nguon":["@c0128"]},{"id":"than-am-phong","name":"Thần âm Phong","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Thần âm Vũ Tử Mạch đọc, bắt chéo hai cánh tay tạo ánh sáng ngăn cú đấm.","detail":"Vũ Tử Mạch đọc Thần âm “Phong!”, bắt chéo hai cánh tay tạo lớp ánh sáng để ngăn cú đấm của Thạch Hạo; nhưng thần lực khủng bố khiến hai cánh tay nàng gãy.","nguon":["@c0129"]},{"id":"than-ha-tay-hoa-song","name":"Thần hà (tay hóa sông lớn)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Bốn đại cường giả (Vũ tộc, Người phong ấn)"],"blurb":"Cường giả phía Đông vung tay biến thành con sông lớn/Thần hà đánh tới.","detail":"Người phong ấn phía Đông vung tay biến thành một con sông lớn (Thần hà) đánh tới đối kháng Thạch Hạo.","nguon":["@c0129"]},{"id":"loi-dinh-than-quang-bao-kinh","name":"Lôi đình thần quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần quang phóng qua bảo kính Toan Nghê để đối kháng Người phong ấn phía Đông.","detail":"Thạch Hạo dùng bảo kính Toan Nghê phóng lôi đình thần quang đối kháng Người phong ấn phía Đông.","nguon":["@c0129"]},{"id":"man-mua-than-luc-huy-diet","name":"Màn mưa thần lực hủy diệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Bốn đại cường giả (Vũ tộc, Người phong ấn)"],"blurb":"Cơn mưa rào tầm tã của bốn cường giả nắm giữ thần lực hủy diệt, đập vào người khiến ho ra máu.","detail":"Bốn Người phong ấn Vũ tộc thi triển màn mưa rào tầm tã mang thần lực hủy diệt; đập thẳng vào người khiến Thạch Hạo ho ra máu, bắn thủng ngực phải Sư Tử chín đầu như cái sàng.","nguon":["@c0129"]},{"id":"chin-phi-kiem-hoang-kim-su-tu","name":"Chín phi kiếm hoàng kim","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Hoàng Kim sư tử chín đầu","soHuu":["Hoàng Kim sư tử chín đầu"],"blurb":"Chín cái đầu của Hoàng Kim sư tử mỗi đầu phun ra một thanh phi kiếm màu hoàng kim rực rỡ chém tới.","detail":"Thủ đoạn công kích của Hoàng Kim sư tử chín đầu khi chặn ải: mỗi trong chín cái đầu phun ra một thanh phi kiếm hoàng kim, tổng chín phi kiếm cùng chém tới; nhóc tỳ né tránh rồi bùng phát tia chớp vô tận đối chọi.","nguon":["@c0121"]},{"id":"than-am-phong-vu-tu-mach","name":"Thần âm Phong","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Thuật đối kháng của Vũ Tử Mạch: đọc Thần âm Phong, bắt chéo hai cánh tay tạo ánh sáng ngăn cú đấm.","detail":"Vũ Tử Mạch đọc Thần âm Phong, bắt chéo hai cánh tay tạo ánh sáng để ngăn cú đấm của Thạch Hạo, nhưng hai cánh tay vẫn gãy trước thần lực khủng bố.","nguon":["@c0129"]},{"id":"nhat-the-hoa-quyen","name":"Nhất Thế Họa Quyển","cn":"","loai":"bi-thuat","loaiLabel":"Bảo Thuật","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Bảo Thuật Thông Linh của Vũ Tử Mạch, dùng ký tự Thông Linh dệt sách cổ Phù Văn phong ấn địch, gần như bất hủ.","detail":"Vũ Tử Mạch triển khai chữ Thông Linh — ký tự màu xanh hình lập phương như có sinh mạng — mở ra quyển sách cổ Phù Văn. Thần thông “Nhất Thế Họa Quyển” xếp ký tự thành bức họa như “Phong Ma quyển đến từ Trời xanh” để phong ấn đối thủ. Phù Văn bị phá lại tái sinh ngay tại chỗ, quyển sách cổ như gánh chịu lực lượng của năm tháng, gần như bất hủ. Về sau nàng còn tái triển bảo thuật dệt bức tranh nhiều màu để phòng ngự lôi quang.","nguon":["@c0128"]},{"id":"phu-van-tam-chan-loi-dinh","name":"Phù Văn chữ cổ (Vũ Tử Mạch)","cn":"","loai":"bi-thuat","loaiLabel":"Thuật","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ Tử Mạch"],"blurb":"Chữ cổ liên miên phát âm thanh và ánh sáng chói mắt, tạm thời chặn Lôi đình thần uy.","detail":"Phù Văn chữ cổ mà thiếu nữ thiên tài Vũ tộc thi triển liên miên phát ra âm thanh và ánh sáng chói mắt, khiến cơ thể nàng thêm xinh đẹp mê người, tạm thời chặn lại Lôi đình thần uy. Khi chủ nhân nổi giận, Phù Văn kịch liệt lay động, quyển sách cổ nhiều màu lúc sáng lúc tối, trông rất bất ổn.","nguon":["@c0128"]},{"id":"long-vu-cat-trung","name":"Lông vũ cắt trứng","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Hỏa Vân Tước","soHuu":["Đại Hồng Điểu"],"blurb":"Thần thông của Đại Hồng Điểu, bắn ra một sợi lông vũ sắc như đao để cắt vỏ trứng.","detail":"Đại Hồng Điểu bắn một sợi lông vũ cắt vỏ trứng Tọa Sơn Điêu, tiết diện phẳng như dùng đao, không rớt một giọt lòng trứng.","nguon":["@c0131"]},{"id":"luyen-hoa-tinh-khi-than","name":"Luyện hóa tinh khí thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Phù văn","soHuu":["Thạch Hạo"],"blurb":"Thủ pháp tu hành: vận chuyển phù văn luyện hóa tinh khí thần từ trứng để chữa thương.","detail":"Thạch Hạo ngồi xếp bằng vận chuyển phù văn, luyện hóa tinh khí thần chứa trong trứng Tọa Sơn Điêu; mọi lỗ máu khép lại, thể phách mạnh hơn, chứng tỏ khả năng hồi phục biến thái như hung thú Thái Cổ.","nguon":["@c0131"]},{"id":"cam-ung-nuoc-vu-toc","name":"Cảm ứng nước của Vũ tộc","loai":"khac","loaiLabel":"Năng lực chủng tộc","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":[],"blurb":"Năng lực cảm ứng nước đặc biệt của Vũ tộc.","detail":"Vũ tộc có năng lực cảm ứng nước; Thạch Hạo và Đại Hồng Điểu không có nên chỉ loáng thoáng cảm ứng được cỗ sóng thần bí trong sa mạc.","nguon":["@c0132"]},{"id":"phap-chi-vu-than","name":"Pháp chỉ Vũ thần","loai":"bi-thuat","loaiLabel":"Bí thuật / Nghi thức","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Vũ Văn Thành"],"blurb":"Nghi thức tế bái của Vũ tộc: lập tế đàn nhỏ đen như mực, đốt giấy vàng hiện văn tự thần âm truyền miệng của Vũ thần để chấn nhiếp linh vật.","detail":"Vũ tộc lập tế đàn, đốt tờ giấy vàng hiện ra pháp chỉ truyền miệng của Vũ thần tổ tiên; chú ngữ thượng cổ vang lên khiến linh đằng sợ nằm rạp, Thái Nhất Chân Thủy đổi thái độ nguyện đi theo Vũ tộc. Kết hợp với di vật Vũ thần (nghiên mực, chặn giấy có hào quang thần thánh) để chứng thực Vũ tộc là hậu duệ Vũ thần.","nguon":["@c0133"]},{"id":"luyen-hoa-thai-nhat-chan-thuy","name":"Luyện hóa Thái Nhất Chân Thủy","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Kỹ thuật vận chuyển phù văn tụ thành từng mảng đan dệt quanh người để luyện hóa và đối kháng thần thủy có linh tính.","detail":"Thạch Hạo vận chuyển phù văn tụ thành từng mảng quấn quanh người, ra sức luyện hóa Thái Nhất Chân Thủy. Do thần thủy có linh tính mạnh, quay lại phản luyện hóa ngược và trùng kích khiến xương cốt kêu răng rắc; cuối cùng một phần nước thần hòa vào máu thịt luyện hóa thành công.","nguon":["@c0135"]},{"id":"than-luc-thien-phu","name":"Thần lực thiên phú","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông thể chất","hePhai":"Thái Cổ di chủng","soHuu":["Thạch Hạo"],"blurb":"Lực lượng thân thể thuần túy của Thạch Hạo; đòn đánh xuyên qua phù văn đánh thẳng vào cơ thể đối thủ gây vỡ xương.","detail":"Thạch Hạo kết hợp phù văn với lực lượng thân thể thuần túy, đòn chưởng đối chưởng khiến Vũ Văn Thiên phun máu và cánh tay đứt thành nhiều đoạn.","nguon":["@c0137"]},{"id":"song-dong-pha-hu-khong","name":"Song đồng phá hư không","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Thạch Nghị","soHuu":["Thạch Nghị"],"blurb":"Năng lực của Thạch Nghị, dùng để phá hư không tìm ra tung tích người khác.","detail":"Vũ tộc kỳ vọng Thạch Nghị dùng Song đồng phá hư không để truy tìm tung tích Thạch Hạo.","nguon":["@c0137"]},{"id":"sam-set-dien-luu-nhoc-ty","name":"Sấm sét điện lưu","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Thần lực thiên phú của Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Thần thông của Nhóc Tỳ sinh tia điện vàng, sấm sét đan xen.","detail":"Nhóc Tỳ vỗ tay làm tan phù văn, sinh tia điện vàng kéo đối thủ ngã gục; tay không đánh tan giao long và vuốt giao, phóng điện lưu tra tấn đám con cháu Võ Vương phủ.","nguon":["@c0138"]},{"id":"bao-thuat-hoa-giao-long","name":"Bảo thuật hóa giao long","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Võ Vương phủ","soHuu":["Thiếu niên cầm đầu Võ Vương phủ"],"blurb":"Thiếu niên cầm đầu quơ tay tạo làn gợn sóng hóa thành giao long vẫy đuôi tấn công.","detail":"Bảo thuật của thiếu niên cầm đầu Võ Vương phủ, tạo làn gợn sóng hóa thành giao long vẫy đuôi đánh về phía Nhóc Tỳ, bị đánh tan.","nguon":["@c0138"]},{"id":"bao-thuat-hoa-dao","name":"Bảo thuật Hỏa đạo","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Tộc Phì Di (Thái Cổ di chủng)","soHuu":["Phì Di"],"blurb":"Tuyệt kỹ Hỏa đạo của tộc Phì Di, phi kiếm bao phủ ánh lửa bổ xuống làm đất nứt lan mấy trăm trượng.","detail":"Bảo thuật Hỏa đạo là tuyệt kỹ của tộc Phì Di. Khi thi triển, phi kiếm được bao phủ trong ánh lửa bổ xuống làm đất nứt lan mấy trăm trượng, khí tức kinh người.","nguon":["@c0140"]},{"id":"long-vu-hoa-mui-ten-nam-mau","name":"Lông vũ hóa mũi tên năm màu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chim Loan năm màu","soHuu":["Chim Loan năm màu"],"blurb":"Thần thông của chim Loan năm màu: chùm lông sặc sỡ hóa mũi tên thần bắn về mi tâm đối thủ.","detail":"Chim Loan năm màu xù lông tấn công, chùm lông vũ sặc sỡ hóa thành mũi tên năm màu bắn về mi tâm đối thủ. Đây là một trong những đòn tấn công của hậu duệ Thần điểu.","nguon":["@c0140"]},{"id":"anh-sang-xanh-nhu-dao","name":"Ánh sáng xanh như đao","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tộc ba mắt","soHuu":["Thiên tài Tộc ba mắt (đệ đệ)"],"blurb":"Thần thông Tộc ba mắt: vạch tay tạo ánh sáng xanh như đao trảm phá thiên địa.","detail":"Thiên tài Tộc ba mắt vạch tay tạo ra ánh sáng xanh như đao, có uy lực trảm phá thiên địa, dùng để chém về đối thủ.","nguon":["@c0140"]},{"id":"than-nguyet-bao-thuat","name":"Thần nguyệt","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Nhóc Tỳ","soHuu":["Nhóc Tỳ"],"blurb":"Bảo thuật của Nhóc Tỳ: vầng trăng bạc trắng óng ánh xuất hiện sau lưng, bay đánh vào binh khí đối thủ.","detail":"Nhóc Tỳ triển Thần nguyệt bạc trắng óng ánh xuất hiện sau lưng, bay đánh vào thần kiếm đỏ của Phì Di, dùng để áp chế và đoạt bảo cụ đối thủ.","nguon":["@c0140"]},{"id":"suc-dia-phu","name":"Súc Địa phù","cn":"縮地符","loai":"bi-thuat","loaiLabel":"Thần phù","phamCap":"Thần phù thời Thượng Cổ","hePhai":"Bốn đại gia tộc","soHuu":["Người mặc áo bào xanh"],"blurb":"Thần phù thời Thượng Cổ, dán dưới lòng bàn chân hóa thành lưu quang di chuyển tức thời; số lần dùng có hạn, giá trị liên thành.","detail":"Súc Địa phù là sản phẩm thời Thượng Cổ, một loại thần phù quý giá. Khi dán dưới lòng bàn chân, nó hóa thành lưu quang giúp người dùng di chuyển tức thời, thoát khỏi hiểm cảnh trong nháy mắt. Người mặc áo bào xanh (một Người phong ấn thuộc bốn đại gia tộc) sau khi bị Nhóc Tỳ đánh nứt xương bả vai đã buộc phải dùng Súc Địa phù để chạy thoát. Số lần dùng có hạn, giá trị liên thành — Thái Cổ di chủng nhận xét hắn không dùng được mấy lần nữa.","nguon":["@c0142"]},{"id":"kim-cuong-than-luc","name":"Kim Cương thần lực","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Bạo Viên","soHuu":["Bạo Viên"],"blurb":"Bảo thuật của Bạo Viên, kích hoạt phù văn Kim Cương khiến thân phình to gấp ba, thần lực kinh khủng.","detail":"Kích hoạt phù văn Kim Cương khiến thân thể Bạo Viên phình to gấp ba lần (tới ba mươi mét), thần lực kinh khủng, có Cầu Long quấn quanh thân; kèm sóng trùng kích (phù văn đen bùng thành hơn mười đợt sóng biển) và hóa thân thành chuông lớn màu đen chụp lấy đối thủ, âm chuông nghiền núi thành bột hiện chữ cổ Phong/Sát/Luyện/Tế.","nguon":["@c0147"]},{"id":"than-van-phu-the","name":"Thần văn phụ thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Bạo Viên","soHuu":["Bạo Viên"],"blurb":"Thần thông hàng ma của Bạo Viên, phù văn hóa áp giáp bảo vệ trên cánh tay.","detail":"Bạo Viên rống lên hiện đại thần thông, phù văn hóa thành áp giáp bảo vệ trên cánh tay, cực bá đạo; kèm thần cương hộ thể (ánh sáng đen rực bảo vệ thân, giúp né đòn trí mạng của Nhóc Tỳ).","nguon":["@c0147"]},{"id":"dong-thuat-toc-ba-mat","name":"Đồng thuật","cn":"瞳術","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thái Cổ di chủng","hePhai":"Tộc ba mắt","soHuu":["Hai huynh đệ tộc ba mắt","Kim Sí Bằng điểu"],"blurb":"Phép thuật thi triển bằng mắt của tộc ba mắt; con ngươi hóa vòng xoáy vàng nuốt chửng linh hồn, mắt dọc thông linh nhìn thấu bản thể bảo cụ.","detail":"Đồng thuật là phép thuật đặc trưng thi triển qua đôi mắt. Với tộc ba mắt, con mắt dọc có thể thông linh, nhìn thấu bản thể và lai lịch của bảo cụ đối phương. Kim Sí Bằng điểu cũng thi triển một dạng đồng thuật: hai mắt biến thành hai vòng xoáy vàng óng muốn nuốt chửng linh hồn, kéo tinh thần đối thủ chìm vào. Nhóc Tỳ phá đòn này bằng luồng tinh khí chí cương chí dương kết hợp tia chớp bắn thẳng vào hai mắt Kim Bằng.","nguon":["@c0149"]},{"id":"dai-bang-giuong-canh","name":"Đại Bằng giương cánh","cn":"大鵬展翅","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt kỹ chủng tộc","hePhai":"Kim Sí Bằng điểu","soHuu":["Kim Sí Bằng điểu"],"blurb":"Tuyệt kỹ chủng tộc của Kim Sí Bằng điểu: chiếc cánh vàng chém tới sắc hơn thiên đao, phù văn màu vàng phủ đầy trời.","detail":"Đại Bằng giương cánh là thần thông chủng tộc của Kim Sí Đại Bằng — hung cầm kiêu ngạo ở Bách Đoạn sơn. Khi thi triển, chiếc cánh vàng chém tới sắc bén còn hơn thiên đao, mang theo phù văn màu vàng phủ đầy bầu trời, cực kỳ đáng sợ. Bảo phiến vàng (cánh Kim Ô) của Bằng điểu khi biến thành cánh thần cũng khuếch đại uy lực của tuyệt kỹ này, kèm thần hỏa và phù văn hủy diệt. Nhóc Tỳ phải đá đùi phải hết lực như vạn tia thần quang mới chặn được cú chém của cánh thần.","nguon":["@c0149"]},{"id":"coi-xay-mau-bac-nhoc-ty","name":"Cối xay màu bạc","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Vô số vòng bảo nguyệt trắng bạc xoay tròn, từng cặp hợp lại nghiền ép mũi tên lông vàng.","detail":"Bảo thuật của Nhóc Tỳ: tạo vô số vòng trăng bạc (thần nguyệt), bên trong có cung điện, cổ thụ, Thanh Thiên Bằng; các bảo nguyệt xoay tròn hợp thành cối xay màu bạc nghiền ép mưa lông vàng của đối thủ, hóa giải đại kiếp nạn mà người khác không ứng phó nổi.","nguon":["@c0150"]},{"id":"chong-chat-bao-thuat","name":"Chồng chất bảo thuật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Kết hợp trăng bạc và tia điện thành vầng thần nguyệt màu vàng chứa Thái Cổ ma cầm và Thiên Bằng vàng.","detail":"Bảo thuật của Nhóc Tỳ: kết hợp trăng bạc với tia điện (lôi hải) thành vầng thần nguyệt màu vàng, bên trong ẩn Thái Cổ ma cầm và Thiên Bằng vàng; là kết quả thí luyện dung hợp hai loại bảo thuật nhiều lần.","nguon":["@c0150"]},{"id":"than-kiem-vang-kim-bang","name":"Thần kiếm vàng","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật","hePhai":"Kim Sí Bằng điểu","soHuu":["Kim Sí Bằng điểu"],"blurb":"Phù văn màu vàng đan dệt thành thanh thần kiếm sắc bén, đại biểu tính ác liệt, phá diệt vạn vật.","detail":"Bảo thuật của Kim Sí Bằng điểu: đan phù văn màu vàng thành thanh thần kiếm sắc bén, đại biểu tính ác liệt cường thế, phá diệt vạn vật; bị Thanh Thiên Bằng của Nhóc Tỳ chụp nát khi đã rạn nứt.","nguon":["@c0150"]},{"id":"dai-bang-chuong","name":"Đại Bằng chưởng","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật","hePhai":"Kim Sí Bằng điểu","soHuu":["Kim Sí Bằng điểu"],"blurb":"Hai cánh hóa đôi bàn tay khổng lồ đánh tới, thần lực có một không hai, thời cổ từng quét ngang chư thần.","detail":"Bảo thuật của Kim Sí Bằng điểu: mắt thành vòng xoáy hút tinh khí thần, hai cánh hóa thành đôi bàn tay khổng lồ đánh tới; thần lực có một không hai, thời cổ từng quét ngang chư thần.","nguon":["@c0150"]},{"id":"than-hi-hoi-phuc","name":"Thần hi","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thuật hồi phục","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Vận chuyển khiến vết thương nhanh chóng khép lại, không để lại sẹo.","detail":"Thuật hồi phục thân thể của Nhóc Tỳ: khi bị móng vuốt suýt xé bụng lòi ruột, vận thần hi khiến vết thương nhanh chóng khép lại, ngay cả một vết sẹo cũng không còn.","nguon":["@c0150"]},{"id":"thieu-dot-tinh-khi-than","name":"Thiêu đốt tinh khí thần tăng tốc","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Thiêu đốt tinh khí thần để tốc độ tăng gấp mấy lần trong thời gian ngắn, dùng lâu sẽ khô cạn máu huyết mà chết.","detail":"Bí thuật của Nhóc Tỳ: trả giá lớn thiêu đốt tinh khí thần để tăng tốc gấp mấy lần trong thời gian ngắn, đuổi giết hung cầm trong mây; nếu dùng lâu sẽ khô cạn máu huyết mà chết vì kiệt sức.","nguon":["@c0151"]},{"id":"tu-huy-phu-cot","name":"Tự hủy phù cốt","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật chí cường","hePhai":"Tộc Đại Bằng","soHuu":["Kim Sí Đại Bằng"],"blurb":"Bảo thuật chí cường của bộ tộc Đại Bằng: tự làm nứt vỡ phù cốt trong thân để không cho đoạt bảo thuật.","detail":"Bảo thuật chí cường của bộ tộc Đại Bằng: Kim Sí Đại Bằng khi thất thế tự làm nứt vỡ toàn bộ phù cốt trọng yếu trong thân, khiến Nhóc Tỳ không lấy được bảo thuật của bộ tộc Đại Bằng.","nguon":["@c0151"]},{"id":"bao-thuat-lam-tan-xuong","name":"Bảo thuật làm tan xương","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bảo thuật","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Nhóc Tỳ dùng làm tan cả xương chân Bạch Hổ thành chất lỏng lóng lánh hào quang khi nấu canh hổ cốt.","detail":"Bảo thuật của Nhóc Tỳ: khi nấu canh hổ cốt từ chân sau Bạch Hổ, dùng bảo thuật làm tan cả xương thành một chất lỏng lóng lánh hào quang tràn đầy để cả đám tranh uống.","nguon":["@c0152"]},{"id":"am-ba-sat-thuong","name":"Âm ba sát thương","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông","hePhai":"Linh tộc","soHuu":["Sinh linh ba đầu Linh tộc"],"blurb":"Tiếng gầm của sinh linh ba đầu tạo sóng âm phá nổ cổ thụ, đánh bay loạn thạch.","detail":"Thần thông của sinh linh ba đầu Linh tộc: tiếng gầm tạo sóng âm phá nổ cổ thụ, đánh bay loạn thạch quanh vùng.","nguon":["@c0153"]},{"id":"bao-cot-phat-sang","name":"Bảo cốt phát sáng","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Thân thể pháp","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Nhóc Tỳ vận bảo cốt phát sáng để ổn định thân thể trước áp lực từ trường trong Thần viên.","detail":"Thân thể pháp của Nhóc Tỳ: vận bảo cốt phát sáng để ổn định thân thể, chống lại áp lực từ trường cực mạnh làm hư không vặn vẹo, xương cốt rung động khi tiến vào Bách Thảo viên (Thần viên).","nguon":["@c0153"]},{"id":"truong-vuc-thu-ho-vuon-thuoc","name":"Trường vực thủ hộ vườn thuốc","cn":"","loai":"khac","loaiLabel":"Cấm trận / Trường năng","phamCap":"Không rõ","hePhai":"Thần viên (vườn linh dược)","soHuu":[],"blurb":"Sức mạnh bí ẩn bao quanh linh dược trong Thần viên, tăng vọt hơn mười lần khi tới gần.","detail":"Trường vực thủ hộ quanh linh dược trong vườn thuốc, mỗi lần có người hái đều bị đánh bật ra, khiến cường giả bình thường nổ tung, người hái phải thổ huyết. Nhóc Tỳ mỗi lần nhổ linh dược đều bị đánh bật, khí huyết nhộn nhạo, ói bốn ngụm máu.","nguon":["@c0154"]},{"id":"bao-thuat-truyen-thua-thai-co-than-son","name":"Bảo thuật truyền thừa Thái Cổ Thần Sơn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thái Cổ Thần Sơn","soHuu":["Hoàng Kim thú"],"blurb":"Thần thông vô lượng Hoàng Kim thú có được do chiếm truyền thừa trong Thái Cổ Thần Sơn, nhưng không thi triển được ở khu vực Bất Lão Tuyền.","detail":"Bảo thuật truyền thừa lấy từ Thái Cổ Thần Sơn cho phép Hoàng Kim thú có thần thông vô lượng, nhưng vì trường vực Bất Lão Tuyền kinh khủng nên không thi triển được, khiến nó chỉ dựa được sức thần thú bán huyết và bị Nhóc Tỳ áp chế.","nguon":["@c0155"]},{"id":"truong-vuc-bat-lao-tuyen","name":"Trường vực Bất Lão Tuyền","cn":"","loai":"khac","loaiLabel":"Lực trường / Trận pháp","phamCap":"Không rõ","hePhai":"Bất Lão Tuyền","soHuu":[],"blurb":"Trường vực cực kỳ kinh khủng quanh thần trì Bất Lão Tuyền, cản các sinh linh cường đại tiếp cận và bảo vệ vườn thuốc khỏi bị hủy diệt.","detail":"Trường vực quanh Bất Lão Tuyền khiến các sinh linh cường đại còn phải đứng ngoài mấy trượng, chưa chiếm được gì; đồng thời cản trở thi triển bảo thuật và bảo vệ vườn thuốc khỏi bị hủy diệt.","nguon":["@c0155"]},{"id":"tieng-rong-chan-dich-chu-kien","name":"Tiếng rống chấn địch","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chư Kiền (hung thú Thái Cổ)","soHuu":["Chư Kiền"],"blurb":"Tiếng gầm như sấm của Chư Kiền, có thể chấn động kẻ địch chết tươi.","detail":"Thần thông thiên phú của hung thú Thái Cổ Chư Kiền: tiếng rống như sấm hoặc chuông thần có thể chấn động kẻ địch chết tại chỗ.","nguon":["@c0157"]},{"id":"108-long-than-hoa-kiem-than","name":"108 lông thần hóa kiếm thần","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thái Cổ","hePhai":"Sinh linh thuần huyết","soHuu":["Tất Phương"],"blurb":"Tất Phương xòe 108 cái lông thần sau lưng hóa thành thanh kiếm thần âm vang, sát khí chấn thập phương.","detail":"Bảo thuật của sinh linh thuần huyết Tất Phương: xòe 108 lông thần sau lưng hóa thành kiếm thần, bay trên trời bổ nhào công kích, sát khí chấn động khắp nơi.","nguon":["@c0159"]},{"id":"roi-than-quang-chu-kien","name":"Roi thần quang","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thái Cổ","hePhai":"Sinh linh thuần huyết","soHuu":["Chư Kiền"],"blurb":"Chư Kiền hiện vầng sáng trên đầu, một cây roi thần quang dâng trào, khí tức như ngân hà lay động.","detail":"Bảo thuật của Chư Kiền: trên đầu hiện vầng sáng, dâng trào một cây roi thần quang truy sát, khí tức mãnh liệt như ngân hà lay động.","nguon":["@c0159"]},{"id":"bao-thuat-ngu-sac-khong-tuoc-vuong","name":"Bảo thuật Ngũ Sắc Khổng Tước Vương","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thái Cổ (trấn thế)","hePhai":"Võ Vương phủ","soHuu":["Thạch Nghị"],"blurb":"Bảo thuật của Thái Cổ thần vương Ngũ Sắc Khổng Tước Vương; Thạch Nghị phun thần quang ngũ sắc trùng kích, là thần thông kinh thế thứ năm hắn thi triển.","detail":"Một trong năm loại bảo thuật trấn thế của Võ Vương phủ (chiếm được từ di chủng, đều không hoàn chỉnh). Thạch Nghị bay vút lên trời phun thần quang ngũ sắc trấn áp Liệt Thiên Ma Điệp; đây là loại thần thông kinh thế thứ năm hắn thi triển.","nguon":["@c0159"]},{"id":"trung-dong-khai-thien","name":"Trùng Đồng Khai Thiên","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Trấn tộc","hePhai":"Trùng Đồng giả","soHuu":["Thạch Nghị"],"blurb":"Thần năng của Trùng Đồng giả: con ngươi phóng ra lưới phù văn kèm thần âm tạo hào quang mịt mù như khai thiên, trói cứng địch thủ và có thể trấn giết.","detail":"Thạch Nghị mở con ngươi bắn ra một tấm lưới phù văn kinh khủng đi kèm thần âm vang vọng, hào quang mịt mù như khai thiên, trói cứng Liệt Thiên Ma Điệp khiến nó khó phóng kiếm quang.","nguon":["@c0160"]},{"id":"bao-thuat-loi-dien-vu-toc","name":"Bảo thuật lôi điện (thần thông trấn giáo Vũ tộc)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Trấn giáo","hePhai":"Vũ tộc","soHuu":["Thạch Nghị"],"blurb":"Thần thông trấn giáo của Vũ tộc — gia tộc mẫu thân Thạch Nghị; thi triển tia chớp chống sấm sét, uy lực hơn cả Vũ tộc.","detail":"Thạch Nghị dùng thần thông lôi điện trấn giáo Vũ tộc đối lôi với bảo thuật sấm sét của Liệt Thiên Ma Điệp, thi triển ra còn mạnh hơn cả Vũ tộc.","nguon":["@c0160"]},{"id":"nam-dai-than-thong-thach-nghi","name":"Năm đại thần thông của Thạch Nghị","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Trấn tộc","soHuu":["Thạch Nghị"],"blurb":"Năm loại bảo thuật trấn tộc của Thạch Nghị, mỗi loại cô đọng thành một mảnh phù văn đưa vào một Động Thiên hóa sinh chim thần mãnh thú Thái Cổ.","detail":"Thạch Nghị nắm giữ năm loại bảo thuật trấn tộc, mỗi loại cô đọng thành một mảnh phù văn đưa vào một Động Thiên, hóa sinh một sinh linh chí tôn Thái Cổ (Khổng Tước ngũ sắc, Bệ Ngạn, Kim Sí Đại Bằng...). Võ Vương phủ + Vũ tộc chỉ giải thích được ba loại, hai loại còn lại nguồn gốc bí ẩn, nghi Võ Vương truyền lại. Biểu hiện luyện bảo thuật đến cảnh giới xuất thần nhập hóa.","nguon":["@c0160"]},{"id":"luyen-hoa-phu-van-nhoc-ty","name":"Luyện hóa phù văn","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thủ pháp Nhóc Tỳ vận chuyển phù văn tụ thành từng mảng đan dệt quanh người để đối kháng và luyện hóa Thái Nhất Chân Thủy.","detail":"Khi cố luyện hóa Thái Nhất Chân Thủy, Nhóc Tỳ vận chuyển phù văn tụ thành từng mảng đan dệt quanh người, vừa đối kháng lực phản luyện hóa của nước thần vừa hấp thu tinh hoa.","nguon":["@c0135"]},{"id":"dai-than-thong-che-giau-khi-tuc","name":"Đại thần thông che giấu khí tức","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Thủ pháp che giấu khí tức Nhóc Tỳ dùng theo lời dặn trưởng bối để giấu mình thoát khỏi vùng săn giết.","detail":"Đại thần thông che giấu khí tức giúp Nhóc Tỳ ẩn giấu khí tức, thoát khỏi cấm khu Thiên Cốt giữa lúc các lão quái đại khai sát giới trong Bách Đoạn sơn.","nguon":["@c0161"]},{"id":"108-cong-than-vu-tat-phuong","name":"108 cọng thần vũ Tất Phương","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Tất Phương"],"blurb":"Trăm lẻ tám cọng thần vũ sau lưng Tất Phương, dao động như tiên kiếm phát bảo huy che phủ cả sườn đồi.","detail":"Khi giao đấu với Nhóc Tỳ, Tất Phương xuất 108 cọng thần vũ dao động như tiên kiếm, phát ra bảo huy che phủ cả sườn đồi để công kích.","nguon":["@c0161"]},{"id":"song-am-buc-long","name":"Sóng âm của Bức Long","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Sóng âm vô hình của đàn Bức Long, xuyên kim liệt thạch, làm thất khiếu chảy máu, đặc biệt hại tai.","detail":"Đàn Bức Long (giống dơi khổng lồ) dùng sóng âm vô hình giết người hàng loạt trong Bách Đoạn sơn; sóng âm xuyên kim liệt thạch, làm thất khiếu chảy máu và đặc biệt hại tai.","nguon":["@c0161"]},{"id":"phu-van-pha-cam-che-than-nu","name":"Phù văn phá cấm chế của thiếu nữ áo tím","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật phù văn","phamCap":"Không rõ","hePhai":"","soHuu":["Thiếu nữ áo tím"],"blurb":"Thuật phù văn phá trận nghịch thiên: phá vỡ từng cấm chế khắp núi mà không gây tiếng động.","detail":"Thiếu nữ áo tím phá vỡ từng cái cấm chế khắp núi mà không gây ra bất cứ tiếng động nào, trình độ phù văn được mô tả kinh khủng nghịch thiên; toàn thân nàng phát phù văn có thể luyện hóa đối phương. Khi bị Nhóc Tỳ tập kích thì phù văn mờ đi, uy lực giảm mạnh.","nguon":["@c0162"]},{"id":"than-thong-doi-nui-lap-bien-co-thu-thiet-huyet","name":"Thần thông dời núi lấp biển của Cổ thụ Thiết Huyết","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Thần thông của cây Cổ thụ Thiết Huyết, rễ cây quật ngã cả ngọn núi.","detail":"Cây cổ thụ mọc lên từ mặt đất phóng rễ cây quật ngã cả ngọn núi, phá sơn mạch, cường thế vô địch.","nguon":["@c0163"]},{"id":"phap-thien-tuong-dia","name":"Pháp Thiên Tượng Địa","cn":"法天象地","aliases":["Pháp Thiên Tướng Địa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật","hePhai":"","soHuu":["Thần Hầu vương"],"blurb":"Bảo thuật khiến thân thể biến to lớn uy mãnh như ngọn núi, tăng chiến lực vô song.","detail":"Thuật khiến thân thể biến to lớn uy mãnh như ngọn núi, tăng chiến lực vô song. Thần Hầu vương dùng biến thành ngọn núi vàng đứng sừng sững, chiến lực vô song đơn đấu quần vương. Nhóc Tỳ nhận ra thân pháp này và tiếc rằng phù văn liên quan trong cơ thể Bóng Lông đã phai mờ.","nguon":["@c0165"]},{"id":"ma-tu-nguyen-rua","name":"Ma Tu nguyền rủa","loai":"than-thong","loaiLabel":"Thần thông / Thần chủng","phamCap":"Không rõ","hePhai":"Bồ Ma thụ","soHuu":["Bồ Ma thụ"],"blurb":"Thần chủng của Bồ Ma thụ, hình như hoa tuyết trắng nõn hoặc tơ trắng, cắm rễ trên da thịt cường giả để hấp thu tinh hoa cả đời.","detail":"Ma Tu nguyền rủa là thần chủng của Bồ Ma thụ, những đóa hoa tuyết trắng nõn bay tới cắm rễ trên da thịt cường giả, mọc rễ hấp thu tinh khí thần. Người nhiễm phải Ma Tu khó thoát khỏi cái chết. Thời Thái Cổ, Ma tôn Bồ Ma thụ từng trồng Ma Tu lên một vị Thần linh, hút sạch tinh khí thần để lột xác. Bản thân hạt Ma Tu cũng là bảo cụ, cứng hơn sắt đá; Nhóc Tỳ đã cắn nhai nuốt luôn.","nguon":["@c0167"]},{"id":"ma-tran-thuong-co","name":"Ma trận Thượng Cổ","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Bồ Ma thụ","soHuu":["Bồ Ma thụ"],"blurb":"Trận pháp Bồ Ma thụ dùng thần chủng ngưng kết với ký hiệu thần bí xếp thành để vây luyện hóa đối thủ.","detail":"Bồ Ma thụ dùng thần chủng Ma Tu ngưng kết cùng các ký hiệu thần bí xếp thành ma trận thời Thượng Cổ, dùng rễ cây như mấy chục cánh tay quấn lấy Nhóc Tỳ, mọc lưỡi dao đâm hút tinh khí thần trong trận. Nhóc Tỳ phá trận bằng cách ăn ngấu nghiến thân cây.","nguon":["@c0167"]},{"id":"dai-tran-phong-thien","name":"Đại trận Phong Thiên","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thần Hầu vương","soHuu":["Thần Hầu vương"],"blurb":"Đại trận với ký hiệu thần bí sáng lóng lánh khóa chặt khu vực, cố định mặt đất khiến không ai rung chuyển được bốn gốc đào tiên.","detail":"Thần Hầu vương bày đại trận Phong Thiên để khóa chặt nơi tranh đoạt và vây gọn kẻ tranh dược, cố định mặt đất và đào tiên. Sau bị Giao già — đại sư trận pháp — phá vỡ một góc, rồi các lão quái cùng phát lực làm đại trận tan rã.","nguon":["@c0168"]},{"id":"kim-than-tu-long-khi","name":"Kim thần từ lông khỉ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thần Hầu vương","soHuu":["Thần Hầu vương"],"blurb":"Vô số lông khỉ trên người Thần Hầu bay ra biến thành kim thần màu vàng đâm thẳng về phía trước.","detail":"Thần Hầu vương thi triển thần thông khiến vô số lông khỉ trên người biến thành kim thần màu vàng đâm thẳng, đâm trúng Li Long khiến hắn đầy máu buông dược bỏ chạy.","nguon":["@c0168"]},{"id":"than-nang-con-nguoi-thach-nghi","name":"Thần năng con ngươi của Thạch Nghị","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thạch Nghị","soHuu":["Thạch Nghị"],"blurb":"Từ con ngươi bay ra nét vẽ như sợi tơ, cố định và giam cầm hư không cùng bảo dược, ngăn mọi người tới gần.","detail":"Thạch Nghị vận thần năng từ con ngươi, phóng ra nét vẽ như sợi tơ cố định hư không và giam cầm bảo dược, tạo cơ hội thu đào tiên vào bình bảo cốt.","nguon":["@c0168"]},{"id":"an-than-van-thieu-nu-ao-tim","name":"Ấn thần vân của thiếu nữ áo tím","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thiếu nữ áo tím","soHuu":["Thiếu nữ áo tím"],"blurb":"Bàn tay như ngọc kết ấn biến ra mảnh thần vân bao phủ đào tiên, lôi về phía mình.","detail":"Thiếu nữ áo tím kết ấn tạo mảnh thần vân bao phủ cây đào tiên rồi lôi về phía mình để tranh đoạt thánh dược.","nguon":["@c0168"]},{"id":"vo-ao-nghia-vo-thuong","name":"Vỡ áo nghĩa vô thượng","cn":"","loai":"than-thong","loaiLabel":"Thần thông biến hình","phamCap":"Không rõ","hePhai":"Nhị Ngốc Tử","soHuu":["Nhị Ngốc Tử"],"blurb":"Thần thông biến hình quái điểu tự xưng đã khám phá, có thể biến thành Kỳ Lân, hóa thành Phượng Hoàng, hình thể tùy tâm biến đổi.","detail":"Quái điểu Nhị Ngốc Tử khoe khám phá vỡ áo nghĩa vô thượng, cho phép biến Kỳ Lân hóa Phượng Hoàng, hình thể tùy tâm biến đổi. Chưa được thi triển rõ trong chương.","nguon":["@c0169"]},{"id":"chin-dong-thien","name":"Chín Động Thiên","loai":"khac","loaiLabel":"Cảnh giới / Kỳ cảnh","phamCap":"Cảnh giới truyền thuyết trong sách cổ","hePhai":"Nhân tộc","soHuu":["Nhóc Tỳ"],"blurb":"Cảnh giới đột phá của Nhóc Tỳ: chín tòa núi lửa Động Thiên xếp chồng giao hòa thiên địa.","detail":"Cảnh giới mà Nhóc Tỳ mở ra khi nhảy xuống núi lửa đột phá, chín tòa Động Thiên xếp chồng do hắn điều khiển như động phủ giao hòa thiên địa. Đây là cảnh giới chỉ được ghi trong sách cổ, gần như bị coi là tin đồn, Nhân tộc rất khó đạt được; các sinh linh Thái Cổ coi người đạt tới ngang hàng Chân Hống, Thao Thiết.","nguon":["@c0170"]},{"id":"bay-muoi-hai-bien-bong-long","name":"Bảy mươi hai biến","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật biến hóa","phamCap":"Không rõ","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Thuật biến hóa hình thế của Nhóc Tỳ (Bóng Lông). Tuy vốn chưa trọn vẹn nhưng được quái điểu không lông chỉ điểm nên đã bổ sung hoàn thiện.","detail":"Thuật biến hóa hình thể lừa được cả Hỏa Linh Nhi lẫn Sư Tử chín đầu. Nhóc Tỳ biến thành sinh linh da vàng nhạt lực lưỡng, trà trộn vào đám sinh linh ra khỏi Bách Đoạn sơn mà không ai nhận ra, trở thành khán giả quan sát.","nguon":["@c0173"]},{"id":"loi-thuat","name":"Lôi Thuật","aliases":["pháp tắc Lôi Đạo","bảo thuật Lôi Đạo","phù văn Lôi đạo","thần thông Lôi đạo"],"loai":"than-thong","loaiLabel":"Thần thông trấn giáo","phamCap":"Thần thông trấn giáo","hePhai":"Bổ Thiên các","soHuu":["Mộ Viêm","Thạch Hạo"],"blurb":"Thần thông trấn giáo của Bổ Thiên các, tu theo pháp tắc phù văn Lôi đạo. Truyền thừa nay tinh túy gần mất; lão tổ Mộ Viêm ngưng kết hết pháp tắc cả đời thành một tấm thần phù.","detail":"Thần thông trấn giáo Bổ Thiên các dựa trên pháp tắc và phù văn Lôi đạo. Lão tổ Mộ Viêm ngưng kết tinh hoa Lôi đạo cả đời thành một ký hiệu Lôi đạo (thần phù); Nhóc Tỳ nhìn mê mẩn thu được lợi ích lớn, được cho phép học từ cốt thư Lôi đạo ở Tàng Kinh các và tới tìm lão tổ giải đáp. Tinh túy truyền thừa gần như đã mất.","nguon":["@c0175"]},{"id":"bao-thuat-bach-long-be-ngan-tieu-thien","name":"Bảo thuật hình Bạch Long / Bệ Ngạn","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Bổ Thiên các","soHuu":["Tiêu Thiên"],"blurb":"Bảo thuật của Tiêu Thiên, cả người tỏa ánh bạc biến ra Bạch Long và Bệ Ngạn màu bạc tấn công.","detail":"Tiêu Thiên vận dụng khi giao chiến với Nhóc Tỳ: toàn thân tỏa ánh bạc, biến hóa ra hình Bạch Long và Bệ Ngạn màu bạc để công kích.","nguon":["@c0176"]},{"id":"bao-thuat-long-chim-tieu-thien","name":"Bảo thuật lông chim","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Bổ Thiên các","soHuu":["Tiêu Thiên"],"blurb":"Bảo thuật của Tiêu Thiên, biến thành đám lông chim trắng mọc cánh đánh từ trên trời xuống như mưa ánh sáng.","detail":"Tiêu Thiên hóa thành vô số lông chim trắng, mọc cánh đánh từ trên cao xuống tựa mưa ánh sáng khi giao đấu với Nhóc Tỳ.","nguon":["@c0176"]},{"id":"hau-quyen-bong-long","name":"Hầu quyền","loai":"cong-phap","loaiLabel":"Quyền pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Bóng Lông"],"blurb":"Quyền pháp Bóng Lông màu vàng luyện quanh đống lửa khi say rượu Hầu Nhi.","detail":"Khi say rượu Hầu Nhi, Bóng Lông màu vàng đứng luyện Hầu quyền quanh đống lửa trong tiệc di chủng.","nguon":["@c0176"]},{"id":"phu-van-dan-det-nhoc-ty","name":"Phù văn đan dệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Thân pháp phù văn khiến Nhóc Tỳ cả người phát sáng, phóng khí tức mạnh mẽ.","detail":"Khi Nhóc Tỳ vận, cả người phát sáng thành màn ánh sáng vàng óng, phóng ra khí tức mạnh mẽ, sức lực một tay nâng nổi mười mấy vạn cân; dùng khi phản kháng Quỷ gia nhưng không địch nổi.","nguon":["@c0177"]},{"id":"co-than-tran-tang-kinh-cac","name":"Cổ Thần trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Bổ Thiên các","soHuu":[],"blurb":"Trận cổ bày dưới nền móng Tàng Kinh các cùng bảo cốt được chôn, khiến kiến trúc trường tồn.","detail":"Trận pháp bày xuống nền móng Tàng Kinh các, kết hợp bảo cốt được chôn bên dưới, khiến kiến trúc trường tồn khó phá hủy qua các thời đại.","nguon":["@c0177"]},{"id":"phu-van-ho-the-kim-si-dai-bang","name":"Phù văn hộ thể của Kim Sí Đại Bằng","cn":"","loai":"cong-phap","loaiLabel":"Thần công hộ thể gốc","phamCap":"Hoàn mỹ hoàn chỉnh nhất của tộc Kim Bằng","hePhai":"Tộc Kim Bằng","soHuu":[],"blurb":"Thần công hộ thể hoàn mỹ hoàn chỉnh nhất của tộc Kim Bằng, là nguồn gốc mà Kim Tuyền Ba Văn công thoát thai.","detail":"Phù văn hộ thể của Kim Sí Đại Bằng, được Nhân tộc biến đổi cho phù hợp mới thành Kim Tuyền Ba Văn công có những chỗ bất phàm.","nguon":["@c0178"]},{"id":"con-bang-bao-thuat","name":"Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Đại thần thông","phamCap":"Đại thần thông Thái Cổ","hePhai":"Chim thần Thái Cổ","soHuu":["Nhóc Tỳ"],"aliases":["bảo thuật Côn Bằng","Côn Bằng"],"blurb":"Đại thần thông cái thế thời Thái Cổ, sinh linh chuyển hóa giữa cá và chim, sinh ra từ việc dung hợp bảo thuật Kim Sí Đại Bằng và Thanh Thiên Bằng.","detail":"Côn Bằng từng xếp vào nhóm mười người/sinh linh mạnh nhất thời Thái Cổ. Nhóc Tỳ dung hợp bảo thuật Kim Sí Đại Bằng và Thanh Thiên Bằng thành một, tạo ra phôi Côn Bằng chuyển hóa lúc vàng lúc xanh giữa cá và chim, uy lực tăng vọt. Nó nhận định đây mới chỉ là khởi đầu, chưa phải Côn Bằng chân chính, muốn tiếp tục nghiên cứu để tái hiện đại thần thông này; khối kim cốt Tế Linh tặng được cho là giúp bảo thuật lột xác thăng hoa.","nguon":["@c0180","@c0181"]},{"id":"kim-si-dai-bang-bao-thuat","name":"Kim Sí Đại Bằng","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật chim Bằng","phamCap":"Bảo thuật cao cấp","hePhai":"Chim Bằng Thái Cổ","soHuu":["Nhóc Tỳ"],"aliases":[],"blurb":"Một trong hai môn bảo thuật chim Bằng mà Nhóc Tỳ dung hợp để tạo ra Côn Bằng.","detail":"Bảo thuật chim Bằng lấy từ di chủng Kim Sí Đại Bằng. Nhóc Tỳ dung hợp bảo thuật này với Thanh Thiên Bằng thành một, khởi nguồn tái hiện đại thần thông Côn Bằng.","nguon":["@c0180"]},{"id":"thanh-thien-bang-bao-thuat","name":"Thanh Thiên Bằng","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật chim Bằng","phamCap":"Bảo thuật cao cấp","hePhai":"Chim Bằng Thái Cổ","soHuu":["Nhóc Tỳ"],"aliases":[],"blurb":"Môn bảo thuật chim Bằng thứ hai Nhóc Tỳ dung hợp cùng Kim Sí Đại Bằng để sản sinh Côn Bằng.","detail":"Bảo thuật chim Bằng được Nhóc Tỳ dung hợp với Kim Sí Đại Bằng thành một; sự kết hợp này có thể sản sinh, biến hóa ra Côn Bằng — con đường tái hiện đại thần thông Thái Cổ.","nguon":["@c0180"]},{"id":"bang-thuat-bao-thuat-bang-toc","name":"Bằng thuật","aliases":["bảo thuật Bằng tộc"],"loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Phù văn tộc chim Bằng","soHuu":["Nhóc Tỳ"],"blurb":"Pháp môn phù văn của tộc chim Bằng; dung hợp quán thông nhiều cốt thư, hóa Thần Bằng ánh vàng cực kỳ mạnh mẽ.","detail":"Bảo thuật dựa trên phù văn tộc chim Bằng. Nhóc Tỳ mượn nhiều cốt thư ở Tàng Kinh các, đắm mình ngộ pháp hơn nửa tháng, dung hợp quán thông phù văn các loài chim, cuối cùng hiểu rõ toàn bộ và có thể diễn biến khai sáng phù văn tương tự. Trong cảnh ngộ đạo, nó thai nghén ra một Thần Bằng chí cường phủ phù văn xanh.","nguon":["@c0181"]},{"id":"thap-cuong-bao-thuat-nguyen-thuy-thai-co","name":"Thập cường bảo thuật nguyên thủy Thái Cổ","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Nguyên thủy tối cường Thái Cổ","hePhai":"Bảo thuật Thái Cổ","soHuu":[],"blurb":"Mười đại bảo thuật nguyên thủy mạnh nhất, tương ứng mười đại chim thần hung thú Thái Cổ; hầu như đã thất truyền.","detail":"Mười bảo thuật nguyên thủy mạnh nhất thời Thái Cổ, mỗi loại ứng với một trong mười đại chim thần hung thú. Đạt được một loại đã đủ ngạo thế bát hoang. Đến nay hầu như đã mất sạch; Côn Bằng thuật là một trong số đó.","nguon":["@c0181"]},{"id":"su-tu-hong-kim-tinh-long-giac-su","name":"Sư Tử hống","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Kim Tình Long Giác Sư","soHuu":["Kim Tình Long Giác Sư"],"blurb":"Kỹ năng gào của Kim Tình Long Giác Sư, gây gió lớn cát bay; bị tiếng rống của Nhóc Tỳ áp chế.","detail":"Pháp thuật gào thét của di chủng Thái Cổ Kim Tình Long Giác Sư, tạo gió lớn cát bay. Khi đối đầu Nhóc Tỳ, tiếng rống của nó bị tiếng rống của Nhóc Tỳ áp chế hoàn toàn.","nguon":["@c0182"]},{"id":"dai-bang-canh-than-nhoc-ty","name":"Đại bàng cánh thần (ánh sáng vàng)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Nhóc Tỳ","soHuu":["Nhóc Tỳ"],"blurb":"Nhóc Tỳ triệu một con đại bàng gương cánh ánh sáng vàng, cánh thần chém đứt đôi con di chủng.","detail":"Nhóc Tỳ triệu ra một con đại bàng có cánh ánh sáng vàng, dùng cánh thần chém xuống chặt đứt đôi con di chủng Kim Tình Long Giác Sư.","nguon":["@c0182"]},{"id":"huyen-bang-thuat","name":"Huyễn Bằng thuật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bằng thuật Trục Lộc học viện","hePhai":"Bằng tộc / Trục Lộc học viện","soHuu":["Thiếu nữ thiên tài Bằng thuật (Trục Lộc học viện)"],"blurb":"Bằng thuật phân thân hóa thành mười mấy bóng mờ ẩn trong lân vũ, làm mê muội thần thức đối thủ.","detail":"Thiếu nữ thiên tài Trục Lộc học viện dùng để hóa thành mười mấy bóng mờ ẩn trong lân vũ, khiến Nhóc Tỳ chém chết bảy tám bóng vẫn không tìm ra chân thân; cuối cùng bị vòng xoáy vàng cảm ứng gợn sóng của Nhóc Tỳ bắt được chân thân và trấn áp.","nguon":["@c0184"]},{"id":"than-bang-cuong-phong","name":"Thần bằng cương phong","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bằng thuật Trục Lộc học viện","hePhai":"Bằng tộc / Trục Lộc học viện","soHuu":["Thiếu nữ thiên tài Bằng thuật (Trục Lộc học viện)"],"blurb":"Giang cặp cánh chim vỗ mạnh tạo vòng xoáy cuồng phong vàng nghiền nát đá và cây cối thành bột mịn.","detail":"Thiếu nữ thiên tài của Trục Lộc học viện dùng, tạo vòng xoáy vàng cuồng phong nghiền nát đá lớn và cây cối thành bột mịn; bị Nhóc Tỳ hóa giải bằng phù văn kết hợp Kim Tuyền Ba Văn công và bảo thuật Côn Bằng.","nguon":["@c0184"]},{"id":"sat-tran-bon-tan-cot","name":"Sát trận bốn tàn cốt","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Sát trận Trục Lộc học viện","hePhai":"Bằng tộc / Trục Lộc học viện","soHuu":["Tứ đại thiếu niên cường giả (Trục Lộc học viện)"],"blurb":"Bốn miếng tàn cốt vàng của di chủng chí cường kết hợp thành bằng trảo, cánh thần, kiếm thần, linh vũ chim bằng hợp thành sát trận.","detail":"Tứ đại thiếu niên cường giả Trục Lộc học viện mỗi người cầm một miếng tàn cốt vàng, kết hợp thành bằng trảo, cánh thần, kiếm thần và linh vũ chim bằng, hợp thành một tòa sát trận để đối phó Nhóc Tỳ; bị cặp cánh Côn Bằng của Nhóc Tỳ chấn cho bốn người hộc máu bay ngược, vòng xoáy vàng hút phù văn khiến họ thất bại thảm hại.","nguon":["@c0184"]},{"id":"than-bang-thuat-truc-loc","name":"Thần Bằng thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật Bằng tộc","hePhai":"Thư viện Trục Lộc","soHuu":["Nhóc Tỳ"],"blurb":"Pháp môn của Thư viện Trục Lộc mà Nhóc Tỳ tiêu hóa để hoàn thiện Côn Bằng thuật.","detail":"Pháp môn liên quan tới bảo thuật Bằng tộc, được Nhóc Tỳ tiêu hóa trong quá trình tu hành một tháng để hoàn thiện Côn Bằng thuật, tái hiện thần thông của Thập cường sinh linh Thái cổ.","nguon":["@c0185"]},{"id":"bo-thien-thuat","name":"Bổ Thiên Thuật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông trấn giáo (thất truyền)","hePhai":"Bổ Thiên Các","soHuu":[],"blurb":"Cổ thuật trong truyền thuyết mà Thạch Nghị có thể đạt được sau khi tiến vào Thượng Cổ Thánh Viện. (+) Thần thông mạnh nhất của Bổ Thiên Các, đã thất truyền từ thời Thượng cổ. [CAN-SOAT-GOP]","detail":"Liễu Lão tiết lộ Bổ Thiên Thuật chính là thần thông mạnh nhất của Giáo, nhưng đã thất truyền từ thời Thượng cổ do một trận chiến khốc liệt — Chư thánh tranh bá, Thần linh phát điên, đến Tế Linh cũng suýt chết. Là bí ẩn lịch sử lớn gắn với nguồn gốc Bổ Thiên Các.","nguon":["@c0186","@c0268"]},{"id":"bao-thuat-loi-dao-tran-giao","name":"Bảo thuật Lôi Đạo trấn giáo","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Bảo thuật trấn giáo","hePhai":"Bổ Thiên Các","soHuu":["Nhóc Tỳ","Mộ Viêm"],"blurb":"Bảo thuật trấn giáo của Bổ Thiên Các liên quan lôi điện, ánh chớp phù văn rườm rà.","detail":"Bảo thuật trấn giáo lôi điện của Bổ Thiên Các; người tu tắm rửa trong ánh chớp. Liên hệ mật thiết với bảo thuật Toan Nghê (cùng pháp môn lôi điện) nên có thể tương hỗ tham khảo. Nhóc Tỳ tu hành và vào linh sơn xin Lôi Tổ Mộ Viêm chỉ điểm.","nguon":["@c0186"]},{"id":"phap-mon-tang-toc-kim-si-dai-bang","name":"Pháp môn tăng tốc bay của Kim Sí Đại Bằng","loai":"cong-phap","loaiLabel":"Pháp môn / phù văn","phamCap":"Pháp môn truyền thừa","hePhai":"Học viện Trục Lộc","soHuu":["Nhóc Tỳ","Đại Hồng Điểu"],"blurb":"Pháp môn của Học viện Trục Lộc truyền thừa từ Kim Sí Đại Bằng, giúp tăng tốc độ bay.","detail":"Phù văn / pháp môn tăng tốc bay truyền thừa từ Kim Sí Đại Bằng của Học viện Trục Lộc. Nhóc Tỳ truyền cho Đại Hồng Điểu, giúp con quạ mọc lại lông và bay nhanh như tia điện chỉ sau nửa tháng.","nguon":["@c0186"]},{"id":"bao-thuat-toan-nghe-nhoc-ty","name":"Bảo thuật Toan Nghê","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đòn sát thủ chí cương chí cường","hePhai":"Nhóc Tỳ","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật của Nhóc Tỳ với con Toan Nghê hoàng kim; sau khi hấp thu Lôi Kiếp Dịch thì lột xác thành đòn sát thủ mang khí tức hủy diệt.","detail":"Con Toan Nghê hoàng kim sau lưng Nhóc Tỳ; sau khi hấp thu Lôi Kiếp Dịch thì lột xác, được phủ phù văn màu tím, cường thịnh hơn nhiều, trở thành đòn sát thủ chí cương chí cường mang khí tức hủy diệt, há miệng phóng tia chớp thông thiên động địa.","nguon":["@c0188"]},{"id":"loi-dao-bao-thuat-nhoc-ty","name":"Lôi Đạo (bảo thuật)","cn":"","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Bảo thuật đỉnh cấp","hePhai":"Lôi đạo","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật Lôi Pháp Nhóc Tỳ vừa tu thành, tỏa tia chớp chí cường chí dương, dưỡng một loại khí vận đặc biệt.","detail":"Nhóc Tỳ tu thành bảo thuật Lôi Đạo, cả người tỏa ra nhuệ khí và tia chớp chí cường chí dương, dưỡng thành khí vận đặc biệt khiến đôi mắt thêm kiên nghị. Một thân tu hành cùng lúc hai đại bảo thuật khiến hai đại thần thông của nó lột xác và thăng hoa, uy lực đỉnh cấp khi quyết đấu.","nguon":["@c0189"]},{"id":"trieu-hoan-may-den-tia-chop-mo-viem","name":"Triệu hoán mây đen tia chớp","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông lôi điện","hePhai":"Lôi đạo","soHuu":["Mộ Viêm"],"blurb":"Thần thông lôi điện của Lôi tổ Mộ Viêm: gọi mây đen từ thiên địa, hai đám mây va nhau tạo tia chớp lớn như núi bổ xuống, đồng thời tăng vọt thực lực người tu lôi.","detail":"Khi Bổ Thiên Các bị vây công, Mộ Viêm triệu hoán hai đám mây đen va vào nhau, tia chớp giáng xuống như núi bổ, đánh cháy khét lão tổ gia tộc Thác Bạt. Là thần thông lôi điện đặc trưng của Lôi tổ.","nguon":["@c0190"]},{"id":"trieu-hoan-sao-bang-thien-ngoai-lao-dang","name":"Triệu hoán sao băng thiên ngoại","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông tận thế","hePhai":"Bổn nguyên Thần Đằng","soHuu":["Tế Linh"],"blurb":"Thần thông của Lão Đằng: phóng dây leo hồ lô lên chín tầng trời, gọi sao băng từ thiên ngoại cùng sấm chớp, ngân hà phù văn tạo hiện tượng tận thế để đánh giết Chí Cường Giả.","detail":"Trong trận quyết chiến trên Cửu Thiên, Lão Đằng dùng thân dây leo hồ lô xanh phóng lên chín tầng trời, triệu hoán sao băng thiên ngoại, sấm chớp và đại dương phù văn như dải ngân hà đánh giết ba Chí Cường Giả.","nguon":["@c0190"]},{"id":"thap-tinh-quan-nhat","name":"Thập Tinh Quán Nhật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Đạo","soHuu":["Mộ Viêm"],"blurb":"Bảo thuật của Nhóc Tỳ, phóng chuỗi quả cầu ánh sáng hiện mười ngôi sao vàng đâm vào một vầng thái dương, kèm sấm chớp tinh khiết. (+) Thần thông Lôi Đạo của Mộ Viêm, mười quả cầu ánh sáng tím bay nối thành đường thẳng dẫn nổ tạo uy năng pháp tắc Lôi Đạo. [CAN-SOAT-GOP]","detail":"Mộ Viêm thi triển Thập Tinh Quán Nhật khi đại chiến cá sấu bạc và hai lão tổ đại giáo: mười quả cầu ánh sáng tím bay nối thành một đường thẳng, mỗi quả to như Mặt Trời, dẫn nổ tạo ra uy năng pháp tắc Lôi Đạo cực mạnh.","nguon":["@c0191","@c0208"]},{"id":"canh-kim-bang","name":"Cánh Kim Bằng","loai":"than-thong","loaiLabel":"Bảo thuật / Thần thông","phamCap":"Không rõ","hePhai":"Kim Sí Đại Bằng","soHuu":["Liễu Lão"],"blurb":"Bảo thuật của Liễu Lão, hiện đôi cánh vàng cắt đứt thiên địa, nhẹ chấn thì giông tố nổi lên.","detail":"Liễu Lão thi triển Cánh Kim Bằng để hóa thành Kim Sí Đại Bằng hình người: hiện đôi cánh vàng có thể cắt đứt thiên địa, nhẹ chấn thì giông tố nổi lên, gần chém đứt đôi Bạch Hổ và giết được nó.","nguon":["@c0191"]},{"id":"nhuc-than-thanh-thanh","name":"Nhục Thân Thành Thánh","loai":"luyen-the","loaiLabel":"Con đường tu hành","phamCap":"Không rõ","hePhai":"Bổ Thiên Các","soHuu":["Liễu Lão"],"blurb":"Con đường tu hành của Liễu Lão, chỉ dựa vào chính bản thân và bảo thuật, không dùng bảo cụ.","detail":"Nhục Thân Thành Thánh là con đường tu luyện chỉ dựa vào chính bản thân và bảo thuật, không dùng bảo cụ, rèn thân thể tự cường tới cực hạn. Liễu Lão đi con đường này nên dù thân thể tinh khí thần sắp khô kiệt vẫn cực mạnh.","nguon":["@c0191"]},{"id":"loi-bao-chuoi-cau-tim","name":"Lôi bạo chuỗi cầu tím","loai":"than-thong","loaiLabel":"Thần thông Lôi Đạo","phamCap":"Không rõ","hePhai":"Lôi Đạo","soHuu":["Mộ Viêm"],"blurb":"Lôi bạo mạnh nhất của Mộ Viêm, chuỗi cầu tím như mã não bùng phát phế bỏ lớp da cá sấu bạc.","detail":"Lôi bạo là chuỗi hình cầu màu tím như mã não bùng phát, thần thông Lôi Đạo mạnh nhất của Mộ Viêm, dùng để phế bỏ lớp da của con cá sấu bạc bá chủ một phương.","nguon":["@c0191"]},{"id":"than-bang-thuat","name":"Thần Bằng Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật biến hóa","hePhai":"Bổ Thiên Các","soHuu":["Các chủ Bổ Thiên Các"],"blurb":"Thuật hóa thân thành sinh linh khác, con đường tu hành gian nan điều kiện hà khắc nhưng uy lực cực lớn.","detail":"Thần Bằng Thuật là bảo thuật biến hóa cho phép người tu hành hóa thân thành sinh linh khác — con đường gian nan, điều kiện hà khắc nhưng uy lực cực lớn. Trong đại chiến Tịnh Thổ, các chủ Bổ Thiên Các thông linh biến thành Thần Cầm — Đại Bằng vàng khổng lồ, sinh cánh thần vàng cuốn gió mạnh và tiếng sấm, giang cánh bay lên rồi đáp xuống. Vì Bằng Tộc khắc chế loài Giao xà, Đại Bằng dùng một đôi móng vuốt sắc bén chộp lấy con Ngân Giao (Giao Vương) rồi xé toạc khiến nó chết thảm.","nguon":["@c0192"]},{"id":"anh-kiem-hon-don","name":"Ánh kiếm Hỗn Độn","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Kiếm khí","hePhai":"Tịnh Thổ","soHuu":["Tế Linh"],"blurb":"Kiếm khí Hỗn Độn phóng ra từ hồ lô màu xanh của Tế Linh.","detail":"Khi Thần Đằng (Tế Linh) khô vàng kiệt lực, hồ lô màu xanh vẫn còn tinh thần khí và sinh cơ, phóng ra ánh kiếm Hỗn Độn chém trúng bả vai một sinh linh hình người đến từ Nghi Sơn khiến máu phụt ra. Đây là đòn phản kích cuối của Lão Đằng khi bị các Chí Cường Giả vây diệt.","nguon":["@c0192"]},{"id":"nhien-huyet-thong-thien-cong","name":"Nhiên Huyết Thông Thiên công","loai":"cong-phap","loaiLabel":"Công pháp tự bạo / cường hóa","phamCap":"Không rõ","hePhai":"Bổ Thiên các","soHuu":["Lâm Mộc sư huynh"],"blurb":"Công pháp thúc đẩy tiềm năng tối đa trong một ngày, chiến lực tăng mấy đến mười lần rồi đốt cạn máu huyết mà chết.","detail":"Môn công pháp cường hóa cực đoan: sau khi triển khai, sinh mệnh chỉ còn thời gian một ngày, chiến lực tăng gấp mấy đến mười lần, đốt cạn máu huyết rồi chết. Lâm Mộc sư huynh triển khai để chặn hậu cho đệ tử Bổ Thiên các thoát khỏi đại kiếp nạn.","nguon":["@c0195"]},{"id":"bao-thuat-cau-thong-tinh-hoa-cua-nuoc","name":"Bảo thuật câu thông tinh hoa của nước","loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Bổ Thiên các","soHuu":[],"blurb":"Môn bảo thuật câu thông tinh hoa của nước, rất quan trọng với Vũ tộc.","detail":"Một môn bảo thuật câu thông tinh hoa của nước do một trưởng lão Bổ Thiên các nắm giữ, có ý nghĩa quan trọng với Vũ tộc. Trong đại kiếp nạn, đây là mục tiêu cướp đoạt của Vũ Phong khi hắn phản sư môn dẫn cường giả Vũ tộc.","nguon":["@c0195"]}]};